d width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#AAAAAA'>&nbsp;</td>";}if ($BetrokkenNietAfstand == 6 || $BetrokkenNietAfstand == 7) { $BetrokkenNietAfstandTabel = "<td width=20 bgcolor='#AAAAAA'>&nbsp;</td><td width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#FFFFFF'>&nbsp;</td><td width='20' bgcolor='#CCCCCC' align='center'><b><font color='#BB0000'>X</font></b></td><td width='20' bgcolor='#AAAAAA'>&nbsp;</td>";}if ($BetrokkenNietAfstand == 8 || $BetrokkenNietAfstand == 9) { $BetrokkenNietAfstandTabel = "<td width=20 bgcolor='#AAAAAA'>&nbsp;</td><td width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#FFFFFF'>&nbsp;</td><td width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#AAAAAA' align='center'><b><font color='#BB0000'>X</font></b></td>";}if ($BetrokkenNietAfstand <3) {$feedback .= "Wanneer je realistisch en met enige afstand naar jezelf kunt kijken is dat een voordeel in deze fase in je leven. Het helpt om overzicht te houden en handige strategie&euml;n te vinden. Aan de andere kant kan afstandelijkheid, zeker wanneer je het combineert met afstand ten opzichte van andere mensen, ook behoorlijk in de weg staan om wat posiever en aardiger naar jezelf te leren kijken. (...)<br>";}if ($BetrokkenNietAfstand >7) {$feedback .= "Het is goed om betrokken te kunnen zijn bij anderen en zeker belangreijk om betrokken te kunnen zijn bij jezelf. Dat moet natuurlijk enig nuchterheid niet in de weg staan (overigens zonder dat het nou gelijk weer droog en saai wordt). Wanneer je werkelijk <i>betrokken</i> kunt raken bij jezelf, bij jouw groei en behoeften, dan is dat een belangrijke pr&eacute; in dit proces. ";}$AanpassenNietAfgrenzen = $AanpassenNietAfgrenzen1 + $AanpassenNietAfgrenzen2 -1;if ($AanpassenNietAfgrenzen == 1 || $AanpassenNietAfgrenzen == 2) { $AanpassenNietAfgrenzenTabel = "<td width=20 bgcolor='#AAAAAA' align='center'><b><font color='#BB0000'>X</font></b></td><td width='20' bgcolor='#CCCCCC'>&nbsp;<