r='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#AAAAAA'>&nbsp;</td>";}if ($PositiefNietKritisch == 5) { $PositiefNietKritischTabel = "<td width=20 bgcolor='#AAAAAA'>&nbsp;</td><td width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#FFFFFF' align='center'><b><font color='#BB0000'>X</font></b></td><td width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#AAAAAA'>&nbsp;</td>";}if ($PositiefNietKritisch == 6 || $PositiefNietKritisch == 7) { $PositiefNietKritischTabel = "<td width=20 bgcolor='#AAAAAA'>&nbsp;</td><td width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#FFFFFF'>&nbsp;</td><td width='20' bgcolor='#CCCCCC' align='center'><b><font color='#BB0000'>X</font></b></td><td width='20' bgcolor='#AAAAAA'>&nbsp;</td>";}if ($PositiefNietKritisch == 8 || $PositiefNietKritisch == 9) { $PositiefNietKritischTabel = "<td width=20 bgcolor='#AAAAAA'>&nbsp;</td><td width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#FFFFFF'>&nbsp;</td><td width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#AAAAAA' align='center'><b><font color='#BB0000'>X</font></b></td>";}if ($PositiefNietKritisch <3) {$feedback .= "Kritisch zijn is niet slecht. Echter het gebeurt nogal eens dat mensen daardoor niet in actie kunnen komen... en een ontwenning is natuurlijk wel typisch iets dat je moet <i>doen!</i>. Wanneer je jezelf de hele tijd op je kop zit te geven dan kijk je wel linker uit. Dan blijf je zitten waar je zit want als je in actie komt geeft dat een gevoel van &quot;het is toch nooit goed genoeg.&quot;<br>";}if ($PositiefNietKritisch >7) {$feedback .= "Niks mis met positief zijn. Echter wanneer je <i>te</i> positief bent over dingen dan gebeurt het nog wel eens dat mensen eigenlijk onvoldoende stil staan bij de ernst van hun verslaving, bij de schade die er in hun omgeving ontstaat door hun gebruik. Soms kan het dan handig zijn om eens na te vragen hoe de mensen in jouw omgeving jouw verslaving beleven?";}$IntuitieNietPlan = $I