td><td width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#FFFFFF'>&nbsp;</td><td width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#AAAAAA' align='center'><b><font color='#BB0000'>X</font></b></td>";}if ($AanvaardenNietHopen <3) {$feedback .= "Met hoop op een goede afloop is natuurlijk niks mis. Aan de andere kant kan overmatig <i>hopen</i> in de toekomst natuurlijk wel maken dat je onvoldoende in beweging komt <i>in het heden</i>.<br>Of het kan je ook behoorlijk ontevreden maken met jezelf zoals je op dit moment bent... Een onvrede die nogal eens wordt weggewerkt met een slokje...<br>";}if ($AanvaardenNietHopen >7) {$feedback .= "Het is goed om realistisch te zijn in het aanvaarden van het moment. Aan de andere kant is <i>al</i> te veel acceptatie natuurlijk wel een punt waardoor het lastig wordt om te bepalen w&agrave;t je wilt gaan veranderen. Want dat er dingen zullen moeten veranderen bij een ontwenning, dat zal ik toch niet hoeven uitleggen? ";}$AfleidingNietBezig = $AfleidingNietBezig1 + $AfleidingNietBezig2 -1;if ($AfleidingNietBezig == 1 || $AfleidingNietBezig == 2) { $AfleidingNietBezigTabel = "<td width=20 bgcolor='#AAAAAA' align='center'><b><font color='#BB0000'>X</font></b></td><td width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#FFFFFF'>&nbsp;</td><td width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#AAAAAA'>&nbsp;</td>";}if ($AfleidingNietBezig == 3 || $AfleidingNietBezig == 4) { $AfleidingNietBezigTabel = "<td width=20 bgcolor='#AAAAAA'>&nbsp;</td><td width='20' bgcolor='#CCCCCC' align='center'><b><font color='#BB0000'>X</font></b></td><td width='20' bgcolor='#FFFFFF'>&nbsp;</td><td width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#AAAAAA'>&nbsp;</td>";}if ($AfleidingNietBezig == 5) { $AfleidingNietBezigTabel = "<td width=20 bgcolor='#AAAAAA'>&nbsp;</td><td width='20' bgcolor='#CCCCCC'>&nbsp;</td><td width='20' bgcolor='#FFFFFF' align='center'><b><font color='#BB0000'>X</